import os
import json
import argparse

import torch
import torch.nn as nn
from torch.utils.data import Dataset, DataLoader
from torchvision import transforms
from PIL import Image
from transformers import CLIPModel

from model import CLIP_MEAN, CLIP_STD, NUM_CLASSES, FEATURE_DIM


class ImageListDataset(Dataset):
    def __init__(self, data_path, split='test'):
        split_file = os.path.join(data_path, f'{split}.txt')
        with open(split_file, 'r') as f:
            rows = [line.strip().split() for line in f if line.strip()]
        self.files = [r[0] for r in rows]
        self.data_path = data_path
        self.transform = transforms.Compose([
            transforms.ToTensor(),
            transforms.Normalize(CLIP_MEAN, CLIP_STD),
        ])

    def __len__(self):
        return len(self.files)

    def __getitem__(self, idx):
        img = Image.open(os.path.join(self.data_path, 'images', self.files[idx])).convert('RGB')
        return self.transform(img)


class LinearHead(nn.Module):
    def __init__(self, in_dim=FEATURE_DIM, num_classes=NUM_CLASSES):
        super().__init__()
        self.fc = nn.Linear(in_dim, num_classes)

    def forward(self, x):
        return self.fc(x)


class MLPHead(nn.Module):
    def __init__(self, in_dim=FEATURE_DIM, hidden_dim=1024, num_classes=NUM_CLASSES, dropout=0.2):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(in_dim, hidden_dim),
            nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(hidden_dim, num_classes),
        )

    def forward(self, x):
        return self.net(x)


@torch.no_grad()
def safe_clip_features(clip_model, x):
    vision_out = clip_model.vision_model(pixel_values=x, return_dict=True)
    pooled = vision_out.pooler_output
    feats = clip_model.visual_projection(pooled)
    feats = feats / feats.norm(dim=-1, keepdim=True).clamp_min(1e-6)
    return feats


def _extract_state_dict(ckpt):
    if isinstance(ckpt, dict):
        if 'state_dict' in ckpt and isinstance(ckpt['state_dict'], dict):
            return ckpt['state_dict']
        if 'model_state_dict' in ckpt and isinstance(ckpt['model_state_dict'], dict):
            return ckpt['model_state_dict']
        if 'model' in ckpt and isinstance(ckpt['model'], dict):
            return ckpt['model']
    return ckpt


def _strip_prefixes(state_dict):
    out = {}
    for k, v in state_dict.items():
        nk = k
        for prefix in ['module.', 'model.', 'classifier.', 'head.']:
            if nk.startswith(prefix):
                nk = nk[len(prefix):]
        out[nk] = v
    return out


def build_head_from_checkpoint(ckpt):
    state_dict = _strip_prefixes(_extract_state_dict(ckpt))
    keys = set(state_dict.keys())

    if 'fc.weight' in keys and 'fc.bias' in keys:
        head = LinearHead()
        head.load_state_dict({'fc.weight': state_dict['fc.weight'], 'fc.bias': state_dict['fc.bias']}, strict=True)
        return head

    if 'net.0.weight' in keys and 'net.0.bias' in keys and 'net.3.weight' in keys and 'net.3.bias' in keys:
        hidden_dim = state_dict['net.0.weight'].shape[0]
        head = MLPHead(hidden_dim=hidden_dim)
        head.load_state_dict({
            'net.0.weight': state_dict['net.0.weight'],
            'net.0.bias': state_dict['net.0.bias'],
            'net.3.weight': state_dict['net.3.weight'],
            'net.3.bias': state_dict['net.3.bias'],
        }, strict=False)
        return head

    if 'weight' in keys and 'bias' in keys and state_dict['weight'].ndim == 2:
        head = LinearHead(in_dim=state_dict['weight'].shape[1], num_classes=state_dict['weight'].shape[0])
        head.fc.weight.data.copy_(state_dict['weight'])
        head.fc.bias.data.copy_(state_dict['bias'])
        return head

    raise RuntimeError(f'Unsupported checkpoint format. Keys sample: {sorted(list(keys))[:20]}')


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, required=True)
    parser.add_argument('--output', type=str, required=True)
    parser.add_argument('--batch_size', type=int, default=256)
    parser.add_argument('--num_workers', type=int, default=8)
    args = parser.parse_args()

    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    ckpt = torch.load(args.checkpoint, map_location='cpu')
    head = build_head_from_checkpoint(ckpt).to(device)
    head.eval()

    clip = CLIPModel.from_pretrained('openai/clip-vit-base-patch16').to(device)
    clip.eval()

    split = 'test' if os.path.exists(os.path.join(args.data_path, 'test.txt')) else 'val'
    ds = ImageListDataset(args.data_path, split=split)
    loader = DataLoader(ds, batch_size=args.batch_size, shuffle=False, num_workers=args.num_workers, pin_memory=True)

    preds = []
    with torch.no_grad():
        for x in loader:
            x = x.to(device, non_blocking=True)
            feats = safe_clip_features(clip, x)
            logits = head(feats)
            preds.extend(logits.argmax(dim=1).cpu().tolist())

    with open(args.output, 'w') as f:
        json.dump({'predictions': preds}, f)


if __name__ == '__main__':
    main()
